// Extract ADR report from request body
const body = $input.item.json.body || $input.item.json;

// --- ICH E2B(R3) minimum required fields ---
const required = ['productName', 'reporterType', 'adverseEvent'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`ICH E2B Validation Failure — Missing required fields: ${missing.join(', ')}`);
}

// Validate reporter type against E2B allowed values
const validReporterTypes = ['physician', 'pharmacist', 'other_healthcare_professional', 'lawyer', 'consumer', 'patient', 'other'];
const reporterType = body.reporterType?.toLowerCase().replace(/ /g, '_') || 'other';
if (!validReporterTypes.includes(reporterType)) {
  throw new Error(`Invalid reporterType '${body.reporterType}'. Must be one of: ${validReporterTypes.join(', ')}`);
}

// Validate dates if provided
const parseDate = (d) => d ? new Date(d) : null;
const eventOnsetDate = parseDate(body.eventOnsetDate);
const drugStartDate = parseDate(body.drugStartDate);
const drugStopDate = parseDate(body.drugStopDate);

if (eventOnsetDate && isNaN(eventOnsetDate.getTime())) {
  throw new Error(`Invalid eventOnsetDate: ${body.eventOnsetDate}`);
}
if (drugStartDate && eventOnsetDate && drugStartDate > eventOnsetDate) {
  throw new Error('Drug start date cannot be after event onset date');
}

// Calculate time-to-onset (days)
const timeToOnsetDays = (drugStartDate && eventOnsetDate)
  ? Math.round((eventOnsetDate - drugStartDate) / (1000 * 60 * 60 * 24))
  : null;

// Reporter classification (ICH E2B A.1.4)
const isHealthcareProfessional = ['physician', 'pharmacist', 'other_healthcare_professional'].includes(reporterType);

// Generate unique ICSR case ID
const caseId = `ICSR-${Date.now()}-${Math.random().toString(36).substr(2, 8).toUpperCase()}`;

// Build normalized PV case
const pvCase = {
  // Case identifiers
  caseId,
  localCaseNumber: body.localCaseNumber || caseId,
  mahName: body.mahName || 'YOUR_COMPANY_NAME',
  productName: body.productName.trim(),
  activeSubstance: body.activeSubstance || null,
  batchNumber: body.batchNumber || null,

  // Reporter (E2B Section A)
  reporterType,
  isHealthcareProfessional,
  reporterName: body.reporterName || null,
  reporterEmail: body.reporterEmail || null,
  reporterCountry: body.reporterCountry || 'US',
  reporterOrganization: body.reporterOrganization || null,

  // Patient (E2B Section B)
  patientInitials: body.patientInitials || body.patientName?.charAt(0) || 'N/A',
  patientAge: body.patientAge ? parseInt(body.patientAge) : null,
  patientSex: body.patientSex || 'unknown',
  patientWeight: body.patientWeight ? parseFloat(body.patientWeight) : null,
  patientHeight: body.patientHeight ? parseFloat(body.patientHeight) : null,
  medicalHistory: body.medicalHistory || [],
  concomitantMedications: body.concomitantMedications || [],

  // Adverse event (E2B Section D)
  adverseEventNarrative: body.adverseEvent.trim(),
  eventOnsetDate: eventOnsetDate ? eventOnsetDate.toISOString() : null,
  eventEndDate: parseDate(body.eventEndDate)?.toISOString() || null,
  outcome: body.outcome || 'unknown',
  dechallenge: body.dechallenge === true || body.dechallenge === 'yes',
  rechallenge: body.rechallenge === true || body.rechallenge === 'yes',

  // Drug information (E2B Section C)
  drugStartDate: drugStartDate ? drugStartDate.toISOString() : null,
  drugStopDate: drugStopDate ? drugStopDate.toISOString() : null,
  doseStrength: body.doseStrength || null,
  dosageFrequency: body.dosageFrequency || null,
  routeOfAdministration: body.routeOfAdministration || 'unknown',
  indicationForUse: body.indicationForUse || null,
  timeToOnsetDays,

  // Calculated fields
  receivedDate: new Date().toISOString(),
  reportSource: body.reportSource || 'spontaneous',
  countryOfOccurrence: body.countryOfOccurrence || body.reporterCountry || 'US',
  status: 'PENDING_DEDUPLICATION',
  processingStage: 'INTAKE'
};

return { json: { pvCase } };

parameters.text:
=You are a senior pharmacovigilance physician and MedDRA coding specialist with expertise in ICH E2A, E2B(R3), FDA 21 CFR 314.81, and EMA GVP Module VI.

Analyze this adverse drug reaction (ADR) report and provide a structured PV case assessment.

**Product Information:**
- Product Name: {{ $json.pvCase.productName }}
- Active Substance: {{ $json.pvCase.activeSubstance || 'Not specified' }}
- Dose / Frequency: {{ $json.pvCase.doseStrength || 'N/A' }} / {{ $json.pvCase.dosageFrequency || 'N/A' }}
- Route of Administration: {{ $json.pvCase.routeOfAdministration }}
- Indication for Use: {{ $json.pvCase.indicationForUse || 'Not specified' }}

**Patient Details:**
- Age: {{ $json.pvCase.patientAge || 'Unknown' }}, Sex: {{ $json.pvCase.patientSex }}
- Weight: {{ $json.pvCase.patientWeight || 'N/A' }} kg
- Medical History: {{ JSON.stringify($json.pvCase.medicalHistory) }}
- Concomitant Medications: {{ JSON.stringify($json.pvCase.concomitantMedications) }}

**Adverse Event:**
- Narrative: {{ $json.pvCase.adverseEventNarrative }}
- Onset Date: {{ $json.pvCase.eventOnsetDate || 'Not specified' }}
- Time to Onset: {{ $json.pvCase.timeToOnsetDays !== null ? $json.pvCase.timeToOnsetDays + ' days' : 'Not calculable' }}
- Outcome: {{ $json.pvCase.outcome }}
- Dechallenge (stopped drug, event improved): {{ $json.pvCase.dechallenge }}
- Rechallenge (restarted drug, event recurred): {{ $json.pvCase.rechallenge }}

**Reporter:**
- Type: {{ $json.pvCase.reporterType }}
- Healthcare Professional: {{ $json.pvCase.isHealthcareProfessional }}
- Country: {{ $json.pvCase.reporterCountry }}

**Assessment Task:**
1. Code the adverse event to MedDRA LLT, PT, HLT, HLGT, and SOC
2. Assess seriousness per ICH E2A criteria (death, life-threatening, hospitalization, disability, congenital anomaly, medically significant)
3. Assess causality using WHO-UMC criteria (certain, probable/likely, possible, unlikely, unassessable)
4. Determine expectedness (expected/listed vs unexpected/unlisted in reference safety information)
5. Calculate regulatory reporting timelines
6. Identify any signal flags or risk factors

**Response Format (JSON only, no markdown):**
{
  "meddraLLT": "Lowest Level Term from MedDRA",
  "meddraPT": "Preferred Term",
  "meddraHLT": "High Level Term",
  "meddraHLGT": "High Level Group Term",
  "meddraSOC": "System Organ Class",
  "meddraVersion": "27.0",
  "seriousness": {
    "isSerious": true,
    "criteria": ["hospitalization"],
    "isFatal": false,
    "isLifeThreatening": false,
    "causedHospitalization": true,
    "causedDisability": false,
    "isCongenitalAnomaly": false,
    "isMedicallySignificant": false
  },
  "causality": {
    "whoUmcAssessment": "probable/likely",
    "causalityRationale": "Brief rationale for causality assessment",
    "dechallengePositive": true,
    "rechallengePositive": false
  },
  "expectedness": "unexpected",
  "expectednessRationale": "Brief explanation",
  "regulatoryReporting": {
    "requiresExpeditedReport": true,
    "reportingTimelineDays": 15,
    "reportingDeadline": "ISO date string",
    "regulatoryBasis": "ICH E2A Section III — Serious unexpected ADR",
    "targetAgencies": ["FDA", "EMA"]
  },
  "severityGrade": "SEVERE",
  "signalFlags": ["known drug class effect", "potential cardiac signal"],
  "riskFactors": ["age > 50", "pre-existing cardiac condition"],
  "additionalWorkup": ["ECG recommended", "cardiac enzyme monitoring"],
  "narrativeSummary": "Brief medically worded case summary for the ICSR",
  "pvRecommendation": "EXPEDITED_REPORT | PERIODIC_REPORT | CLOSE_MONITOR | NO_ACTION",
  "confidenceLevel": "HIGH | MEDIUM | LOW"
}

parameters.jsCode:
const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle Anthropic content array format
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Strip markdown code blocks
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let medicalCoding;
try {
  medicalCoding = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse Claude AI medical coding: ${error.message}. Raw: ${cleanText.substring(0, 200)}`);
}

// Pull the PV case from upstream
const pvCase = $('Validate and Normalize ADR Intake').item.json.pvCase;

// Merge medical coding into PV case
pvCase.status = 'CODED';
pvCase.processingStage = 'MEDICAL_CODING';
pvCase.codedAt = new Date().toISOString();
pvCase.codedBy = 'Claude AI PV Engine v1 (ICH E2B R3)';

return {
  json: {
    pvCase,
    medicalCoding,
    isSerious: medicalCoding.seriousness?.isSerious || false,
    requiresExpeditedReport: medicalCoding.regulatoryReporting?.requiresExpeditedReport || false,
    reportingDeadlineDays: medicalCoding.regulatoryReporting?.reportingTimelineDays || 15
  }
};

// Pull all historical cases for this product+PT combination
const historicalCases = $('Signal Detection — Query Historical PV Database').all().map(i => i.json);
const currentData = $('Parse AI Medical Coding Output').item.json;

// --- Proportional Reporting Ratio (PRR) and Reporting Odds Ratio (ROR) ---
// Using simplified 2x2 contingency table approach
// a = reports of drug+event, b = reports of drug+other events
// c = reports of other drugs+event, d = reports of other drugs+other events

const totalHistoricalCases = historicalCases.length;
const casesWithSamePT = historicalCases.filter(
  c => c.meddraPT === currentData.medicalCoding.meddraPT
).length;
const casesWithSameProduct = historicalCases.filter(
  c => c.productName === currentData.pvCase.productName
).length;

// Signal thresholds (EMA standard: PRR >= 2, chi-squared >= 4, n >= 3)
const PRR_THRESHOLD = 2.0;
const ROR_THRESHOLD = 2.0;
const MIN_CASES_FOR_SIGNAL = 3;

// Simplified PRR calculation
let prr = null;
let ror = null;
let signalDetected = false;
let signalStrength = 'NONE';

if (totalHistoricalCases >= MIN_CASES_FOR_SIGNAL && casesWithSamePT > 0) {
  const a = casesWithSamePT; // drug + event
  const b = casesWithSameProduct - casesWithSamePT; // drug + other events
  const c = totalHistoricalCases - casesWithSameProduct; // other drugs + event (proxy)
  const d = totalHistoricalCases - a - b - c;

  // PRR = (a / (a+b)) / (c / (c+d))
  if (b > 0 && c > 0 && d > 0) {
    prr = parseFloat(((a / (a + b)) / (c / (c + d))).toFixed(2));
    // ROR = (a/b) / (c/d) = (a*d) / (b*c)
    ror = parseFloat(((a * d) / (b * c)).toFixed(2));
  }

  if (prr && prr >= PRR_THRESHOLD && a >= MIN_CASES_FOR_SIGNAL) {
    signalDetected = true;
    signalStrength = prr >= 5 ? 'STRONG' : prr >= 3 ? 'MODERATE' : 'WEAK';
  }
}

// Cumulative case count for this product+PT
const cumulativeCaseCount = casesWithSamePT + 1; // +1 for current case

// Time trend: cases in last 90 days
const ninetyDaysAgo = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000);
const recentCases = historicalCases.filter(c => {
  const d = new Date(c.receivedDate);
  return d > ninetyDaysAgo && c.meddraPT === currentData.medicalCoding.meddraPT;
}).length;

return {
  json: {
    pvCase: currentData.pvCase,
    medicalCoding: currentData.medicalCoding,
    isSerious: currentData.isSerious,
    requiresExpeditedReport: currentData.requiresExpeditedReport,
    reportingDeadlineDays: currentData.reportingDeadlineDays,
    signalAnalysis: {
      prr,
      ror,
      signalDetected,
      signalStrength,
      cumulativeCaseCount,
      recentCases90Days: recentCases,
      totalHistoricalCases,
      analysisMethod: 'PRR/ROR Disproportionality Analysis',
      analysisThresholds: { prrThreshold: PRR_THRESHOLD, rorThreshold: ROR_THRESHOLD, minCases: MIN_CASES_FOR_SIGNAL },
      signalNotes: signalDetected
        ? `Signal detected: PRR=${prr}, ROR=${ror} (${signalStrength}). ${cumulativeCaseCount} cumulative cases for ${currentData.medicalCoding.meddraPT} with ${currentData.pvCase.productName}.`
        : `No signal threshold crossed. ${cumulativeCaseCount} cumulative case(s) on file.`
    }
  }
};

const data = $('Compute Disproportionality Signal (PRR/ROR)').item.json;

return {
  json: {
    success: true,
    caseId: data.pvCase.caseId,
    productName: data.pvCase.productName,
    receivedDate: data.pvCase.receivedDate,
    processingStatus: 'PROCESSED',
    medicalCoding: {
      meddraPT: data.medicalCoding.meddraPT,
      meddraSOC: data.medicalCoding.meddraSOC,
      meddraLLT: data.medicalCoding.meddraLLT,
      severityGrade: data.medicalCoding.severityGrade,
      causality: data.medicalCoding.causality?.whoUmcAssessment,
      expectedness: data.medicalCoding.expectedness
    },
    seriousness: data.medicalCoding.seriousness,
    regulatoryReporting: data.medicalCoding.regulatoryReporting,
    signalAnalysis: data.signalAnalysis,
    pvRecommendation: data.medicalCoding.pvRecommendation,
    confidenceLevel: data.medicalCoding.confidenceLevel,
    processedAt: new Date().toISOString()
  }
};
